// remux.c - تغيير الحاوي (container) بدون إعادة ترميز
#include <libavformat/avformat.h>
#include <stdio.h>

int main(int argc, char **argv) {
    if (argc < 3) {
        printf("الاستخدام: %s <ملف_مدخل> <ملف_خرج>
", argv[0]);
        return 1;
    }

    AVFormatContext *in_fmt = NULL;
    AVFormatContext *out_fmt = NULL;
    AVPacket *pkt = av_packet_alloc();

    // فتح المدخل
    avformat_open_input(&in_fmt, argv[1], NULL, NULL);
    avformat_find_stream_info(in_fmt, NULL);

    // إعداد الخرج
    const AVOutputFormat *out_fmt_desc = av_guess_format(NULL, NULL, argv[2]);
    avformat_alloc_output_context2(&out_fmt, out_fmt_desc, NULL, argv[2]);

    // نسخ streams
    for (unsigned i = 0; i < in_fmt->nb_streams; i++) {
        AVStream *out_stream = avformat_new_stream(out_fmt, NULL);
        avcodec_parameters_copy(out_stream->codecpar, in_fmt->streams[i]->codecpar);
    }
    avformat_write_header(out_fmt);

    // نسخ الـ packets كما هي
    while (av_read_frame(in_fmt, pkt) >= 0) {
        av_interleaved_write_frame(out_fmt, pkt);
        av_packet_unref(pkt);
    }

    av_write_trailer(out_fmt);
    avformat_close_input(&in_fmt);
    avformat_free_context(out_fmt);
    printf("تم الـ remux بنجاح
");
    return 0;
}
